CREATE TABLE IF NOT EXISTS enregistrement (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    heure_mesure TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    valeur_ph REAL NOT NULL,
    etat_pompe INTEGER NOT NULL CHECK (etat_pompe IN (0, 1))
);

CREATE TABLE IF NOT EXISTS moteur (
    id INTEGER PRIMARY KEY,
    compteur INTEGER,
    start TIMESTAMP,
    end TIMESTAMP
    );

