// Générer 4 enregistrements pour la table moteur
const insertQueries = [];
for (let i = 1; i <= 4; i++) {
    const compteur = Math.floor(Math.random() * 100); // Valeur aléatoire pour compteur
    const start = new Date().toISOString(); // Date actuelle pour start
    const end = new Date(Date.now() + (i * 1000 * 60)).toISOString(); // Date future pour end
    insertQueries.push(`(${i}, ${compteur}, '${start}', '${end}')`);
}

msg.topic = `
INSERT INTO moteur (id, compteur, start, end) 
VALUES ${insertQueries.join(', ')};
`;
return msg;

